import{_ as p,o as t,c as s,ag as r}from"./chunks/framework.ETe_P6d1.js";const e="/kaiping-reports/assets/1.B8eNQpiR.jpg",i="/kaiping-reports/assets/1.DM5Gi7gg.jpg",o="/kaiping-reports/assets/3.DKx4ZeC_.jpg",_="/kaiping-reports/assets/4.DgDsrtXh.jpg",n="/kaiping-reports/assets/5.Dwu7Pr51.jpg",c="/kaiping-reports/assets/6.D6s979i4.jpg",l="/kaiping-reports/assets/7.Cj612a0f.jpg",h="/kaiping-reports/assets/8.JRe5OwTf.jpg",g="/kaiping-reports/assets/9.BpUP5hEh.jpg",m="/kaiping-reports/assets/10.Dro7EqxH.jpg",j=JSON.parse('{"title":"开平立园：空间形态、中西建筑对话呈现调研分析","description":"","frontmatter":{},"headers":[],"relativePath":"reports/李晓镔/开平立园：空间形态、中西建筑对话呈现调研分析.md","filePath":"reports/李晓镔/开平立园：空间形态、中西建筑对话呈现调研分析.md"}'),d={name:"reports/李晓镔/开平立园：空间形态、中西建筑对话呈现调研分析.md"};function u(k,a,f,q,b,P){return t(),s("div",null,[...a[0]||(a[0]=[r('<h1 id="开平立园-空间形态、中西建筑对话呈现调研分析" tabindex="-1">开平立园：空间形态、中西建筑对话呈现调研分析 <a class="header-anchor" href="#开平立园-空间形态、中西建筑对话呈现调研分析" aria-label="Permalink to &quot;开平立园：空间形态、中西建筑对话呈现调研分析&quot;">​</a></h1><p><strong>作者：李晓镔</strong></p><p>考察地点：广东省江门市开平市</p><p>考察时间：2026年3月31日</p><p>指导教师：石拓 教授</p><h2 id="一、引言" tabindex="-1">一、引言 <a class="header-anchor" href="#一、引言" aria-label="Permalink to &quot;一、引言&quot;">​</a></h2><p>开平侨乡作为世界文化遗产地，留存了大量独具地域特色的近代建筑遗产，碉楼、侨宅、私家园林共同构成了近代岭南侨乡完整的建筑体系。在众多遗存之中，立园区别于以防御为核心功能的传统碉楼，是旅美华侨谢维立家族营建的私家庄园，兼具居住、休闲、景观营造与家族社交等多重空间功能，是近代岭南侨乡近代园林建筑的典型范例。结合知网相关学术研究与实地调研成果，本次报告围绕三个维度展开分析。首先从整体布局、组团划分、空间层级、路径结构出发，剖析立园原生空间类型、空间秩序与整体形态特征，结合空间句法相关理论研究其空间结构演变规律；其次分析建筑本体、园林景观、细部构造当中中式传统营造与西方近代建筑元素的融合方式，梳理二者跨文化对话的内在逻辑；最后立足于当下遗产保护现状，探讨立园由私人宅邸转向公共景区后的博物馆化呈现模式，分析该保护模式的优势局限，并结合建筑遗产理论进行批判性思考，总结近代侨乡园林遗产保护与活化的参考价值。</p><h2 id="二、空间类型与空间形态结构分析" tabindex="-1">二、空间类型与空间形态结构分析 <a class="header-anchor" href="#二、空间类型与空间形态结构分析" aria-label="Permalink to &quot;二、空间类型与空间形态结构分析&quot;">​</a></h2><p>结合空间句法相关研究视角来看，立园整体空间形态具备清晰的组团划分、层级秩序与流线结构，整体空间布局区别于传统中式古典园林与西方几何式庄园，形成独属于近代侨乡私园的复合型空间形态。全园整体划分为别墅区、大花园、小花园三大独立又相互连通的空间组团，以自然水系作为全园空间骨架，通过围墙、连廊、拱门、滨水路径划分空间边界，各个组团既保持空间独立性，又依靠线性交通空间实现整体串联。</p><p>在空间类型划分上，园区内部可划分为建筑居住空间、景观游赏空间、过渡灰空间、礼制附属空间四大类。建筑私密空间集中于园区内侧，建筑单体围合形成内向型院落空间，空间围合度高，界面封闭性强，院落内部多设置小型绿植与休闲石桌，适配家族日常起居、亲友闲谈等私密活动，主要承担日常居住功能；园林景观空间开阔舒展，以水体、植被、场地构成开放性景观基底，水体周边搭配岭南特色绿植，如榕树、芭蕉、勒杜鹃等，营造自然灵动的景观氛围，承担休闲游赏、家族社交等功能；贯穿全园的回廊、巷道、临水步道属于典型线性过渡空间，回廊采用木质结构搭配青砖铺地，巷道曲折迂回，临水步道紧贴水系，既承担空间连通、视线引导、场景转换的作用，又能让游人在行走中感受空间的开合变化，通过曲折迂回的路径弱化空间边界，形成开合交替、藏露相间的空间节奏；牌坊、礼制性牌楼等附属空间构成核心节点，采用钢筋混凝土仿石结构，造型庄重，统领大花园空间秩序，兼具礼仪象征与空间界定作用，成为连接不同空间组团的视觉纽带。</p><p>从整体空间形态演变来看，立园原生空间结构以私家生活使用为核心逻辑，内部空间连接度围绕居住需求排布，内部院落连通性强，外部景观空间发散延展，空间节点疏密有致，整体遵循岭南造园灵活自由的布局特征，并未采用西方庄园严格对称的轴线几何形态。空间内部层级分明，由内至外形成私密居住—半私密廊道—开放园林的递进式空间序列，空间界面由封闭逐步转向通透，空间尺度由紧凑逐步转向开阔。各空间组团依靠线性廊道完成有机整合，在有限场地内形成丰富多变的空间层次，整体结构稳定且空间转换富有韵律。</p><p>随着场地功能转变，原生空间结构也产生明显形态变化。私人使用时期空间动线围绕家族起居、日常活动形成闭环式内部流线，空间使用率集中于建筑院落内部，各空间节点的连接度与整合度均围绕生活需求排布，呈现出“私密化、集约化”的空间特征；后期面向公众开放之后，空间结构被重新梳理，原生内部私密路径逐步开放，外部游览路径成为主导，原本紧凑的院落空间被纳入公共游览体系，空间连接节点、通行路径、空间主次关系均发生结构性调整。结合空间句法分析来看，转型后的立园空间整合度重心从居住院落转向公共廊道与景观节点，空间可达性显著提升，整体呈现出传统私园向公共园林“公园化”转型的典型空间演变特征。这种形态变化既满足了公共文化展示的需求，也在一定程度上保留了原生空间的组团格局与核心形态，实现了空间功能与遗产保护的初步平衡。</p><h2 id="三、中西建筑文化的对话-形式融合与跨文化共生" tabindex="-1">三、中西建筑文化的对话：形式融合与跨文化共生 <a class="header-anchor" href="#三、中西建筑文化的对话-形式融合与跨文化共生" aria-label="Permalink to &quot;三、中西建筑文化的对话：形式融合与跨文化共生&quot;">​</a></h2><p>立园的核心建筑价值的在于中西建筑文化的系统性融合，而非简单元素拼贴，其以中式空间格局为骨架、西方建筑形态为表现，其中柱式运用与屋顶形式的搭配是最具代表性的体现，彰显了近代民间跨文化营造智慧。</p><p>立园建筑柱式均采用西方古典柱式，主要有“爱奥尼”和“科林斯”两种类型，组合形式涵盖壁柱式、巨柱式、叠柱式及券柱式，均为西方古典建筑经典立面构图手法。柱式主要用于建筑正面入口，强化门厅视觉焦点，其他立面仅以简单壁柱修饰，实现装饰与实用的平衡。具体而言，晃庐用巨柱式凸显雄伟气势，炯庐以叠柱式丰富立面层次，泮立楼采用“帕拉迪奥母题”券柱式适配建筑尺度，这些西方柱式与开平传统民居空间格局有机结合，形成独特建筑景观。</p><p>屋顶形式则融合了中式坡屋顶与西式平屋顶，暗含建筑地位与家族威望。核心建筑泮立楼、泮文楼采用最高等级的中式庑殿顶，毓培别墅结合重檐歇山顶与六角攒尖顶；其他庐舍采用西式平屋顶并搭配中式装饰；辅助用房用传统硬山顶弱化存在感。这种差异化搭配实现了中西融合，也体现了建筑等级差异。</p><p>此外，建筑单体以西方立面、中式空间为核心，园林则融合岭南自然造园与西方规整景观；细部装饰上，岭南传统工艺与西方装饰元素共存，均体现了中西建筑的深度对话与自主融合。</p><h2 id="四、结论" tabindex="-1">四、结论 <a class="header-anchor" href="#四、结论" aria-label="Permalink to &quot;四、结论&quot;">​</a></h2><p>开平立园作为近代岭南侨乡私园的典型案例，其空间形态与中西建筑融合特征极具研究价值。空间上，园区形成组团清晰、层级分明的复合型形态，呈现出传统私园向公共园林“公园化”转型的典型特征；建筑上，以西方古典柱式与中式屋顶的融合为核心，实现了中西建筑元素的和谐共生，彰显了近代民间跨文化营造智慧。总体而言，立园的空间营造逻辑与建筑融合方式，为近代侨乡同类园林遗产的研究与保护提供了重要参考，丰富了中国近代建筑史的多元内涵。其空间营造逻辑与跨文化建筑融合智慧，不仅彰显了近代侨乡建筑的独特价值，更丰富了中国近代建筑史的多元内涵，为当代同类建筑遗产的保护与传承提供了重要借鉴。</p><h2 id="五、附录-调研记录" tabindex="-1">五、附录：调研记录 <a class="header-anchor" href="#五、附录-调研记录" aria-label="Permalink to &quot;五、附录：调研记录&quot;">​</a></h2><p>摄影记录：本报告共插入10张现场照片，分别展示如下：</p><p><img src="'+e+'" alt="图1：立园鸟瞰图"></p><p><img src="'+i+'" alt="图2：立园景区导览图"></p><p><img src="'+o+'" alt="图3：回廊、巷道、临水步道局部图"></p><p><img src="'+_+'" alt="图4：回廊、巷道、临水步道局部图"></p><p><img src="'+n+'" alt="图5：立园的核心建筑"></p><p><img src="'+c+'" alt="图6：立园建筑柱式"></p><p><img src="'+l+'" alt="图7：屋顶形式"></p><p><img src="'+h+'" alt="图8：屋顶形式"></p><p><img src="'+g+'" alt="图9：建筑单体立面平面装饰"></p><p><img src="'+m+'" alt="图10：建筑单体立面平面装饰"></p><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><p>[1] 武欣,曾丽娟,吴文坤.空间句法视角下近代传统私园“公园化”空间结构演变研究——以开平立园为例[J].城市建筑,2024.</p><p>[2] 王紫琪.开平碉楼建筑装饰中的文化交融——以立园泮立碉楼为例[C].中国民居建筑学术年会论文集,2018.</p><p>[3] 陆元鼎.广东民居建筑[M].北京:中国建筑工业出版社,2017.</p><p>[4] 广东省文物考古研究所.开平碉楼与村落世界文化遗产保护研究[M].北京:文物出版社,2007.</p><p>报告撰写人：李晓镔</p><p>报告完成时间：2026年4月16日</p>',38)])])}const D=p(d,[["render",u]]);export{j as __pageData,D as default};
